VALUES
  ('elementary-6e11b43e-moex-00099', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '教育部與原住民族委員會共同訂定大專校院健康照護相關科系融入原住民族健康事務文化安全課程實施 辦法，其訂定的法源依據為何？', '["原住民族基本法", "原住民族教育法", "原住民族健康法", "原住民族工作權保障法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00100', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-ea33d64d', 'sub-elementary-6e11b43e-02', NULL, 'single_choice', '「為蒐藏、保存、研究原住民族文獻、歷史與文物，中央目的事業主管機關應設置原住民族博物館，推動 原住民族文化永續發展」此一條文，係明定於下列何項法規之中？', '["原住民族基本法", "文化基本法", "原住民族教育法", "博物館法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:55+00:00", "source_pdf_sha1": "c52cfd10ec2a", "answer_pdf_sha1": "02f86109cb69", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "原住民族行政及法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00101', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-34c7f7f6', 'sub-elementary-6e11b43e-03', NULL, 'single_choice', '下列文句「」中的成語用法，何者正確？', '["當一個人做事「行不由徑」，信用和形象都已被打折扣", "她講話總是「拾人牙慧」，充滿個人獨特的想法與見解", "上司若為人正直，行事端正，相信下屬也會「群起效尤」", "工作要先計畫周全再開始執行，才能收「事半功倍」之效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00102', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-34c7f7f6', 'sub-elementary-6e11b43e-03', NULL, 'single_choice', '下列選項句中的「窮」字，何者意義與其他三者不同？', '["明經博覽，無不「窮」究", "君子固「窮」，小人窮斯濫矣", "兩家子孫各長大，他年「窮」達毋相忘", "多有之者富，少有之者貧，至無有者「窮」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00103', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-34c7f7f6', 'sub-elementary-6e11b43e-03', NULL, 'single_choice', '下列情境語句，何者使用錯誤？', '["那雙「骨碌碌」的眼睛轉啊轉，不知在打什麼主意", "芭蕾舞者「活跳跳」的表演，看得觀眾都目不轉睛", "吃完這碗湯麵後，全身「熱呼呼」的，真是舒服啊", "此刻小張的心緒一定是「亂紛紛」的，別打擾他了"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00104', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-34c7f7f6', 'sub-elementary-6e11b43e-03', NULL, 'single_choice', '下列文句「」中的成語，運用恰當的是：', '["太魯閣風景「美輪美奐」，吸引遊客們駐足觀賞", "對於公司未來的發展，千萬不可「目無全牛」胡亂想像", "懲處違法亂紀的「始作俑者」，才能達到殺雞儆猴的效果", "夫妻之間「相敬如賓」，往往會讓旁人以為他們感情不好"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00105', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-34c7f7f6', 'sub-elementary-6e11b43e-03', NULL, 'single_choice', '下列文句「」內的成語，何者替換成語後，文意不變？', '["他長期研究植物，提出許多具「真知灼見」的論文／略陳管見", "這是一部非常精密儀器，務必「小心翼翼」地操作／謹言慎行", "你要認真工作，千萬不可「玩日愒歲」，貪圖享樂／年深月久", "思考必須靈活變通，不宜「刻舟求劍」，拘泥不化／膠柱鼓瑟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00106', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-34c7f7f6', 'sub-elementary-6e11b43e-03', NULL, 'single_choice', '下列文句，何者沒有冗贅字詞？', '["由於雞蛋的需求量大，難怪不得市場的價格始終居高不下", "我竭盡所能地大聲哭著，但是到後來，卻聽不到自己的哭聲", "入夜後風雨仍然持續很大，一團朦朧的亮光卻已然在斜斜上空升起", "泰雅人的山田，大多數多在山坡、谷底，遠離部落，往返通常十分費時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00107', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-34c7f7f6', 'sub-elementary-6e11b43e-03', NULL, 'single_choice', '下列文句「」中的成語，運用最恰當的選項是：', '["將凌亂的衣服鞋襪收納好後，臥房「環堵蕭然」，煥然一新", "這對兄弟從小「琴瑟友之」，長大後更成為生意上的合夥人", "他管理公款卻監守自盜，如今身敗名裂，真是「咎由自取」", "眼看珍藏多年的圖書都在大水中「付之一炬」，他難過不已"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('elementary-6e11b43e-moex-00108', 'elementary-6e11b43e', 'elementary-6e11b43e-moex-114-34c7f7f6', 'sub-elementary-6e11b43e-03', NULL, 'single_choice', '「美國食品暨藥物管理局（FDA）為簡化接種疫苗策略，建議健康成年人每年接種1劑最新 型的新冠肺炎疫苗，類似每年接種流感疫苗。目前多數美國人間隔3至4週，施打2劑原始 病毒株疫苗，數月後再打加強劑。FDA將徵詢專家可否將雙價疫苗指定為初次接種疫苗，如 獲通過，代表疫苗公司針對Omicron病毒株與原始病毒株所研發的雙價疫苗，將不僅限用於 加強劑。」 根據上文，下列選項錯誤的是：', '["雙價疫苗可能作為每年都施打的疫苗", "雙價疫苗現在僅在施打第三劑時使用", "已經打過三劑之民眾明年可免除施打", "多數美國人一年要施打三劑新冠疫苗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:56+00:00", "source_pdf_sha1": "dc62ea810384", "answer_pdf_sha1": "ad957d5f3d5b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "504", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "原住民族行政"}'::jsonb, NULL)
